window.CA = {"date": "Saturday, 27 June 2026", "updated": "2026-06-27 17:44", "updated_label": "27 Jun 2026, 17:44 IST", "items": [{"title": "PM Modi Visits Seychelles as Guest of Honour at Golden Jubilee National Day Celebrations", "category": "ir", "category_name": "International Relations", "summary": "Prime Minister Narendra Modi travelled to Seychelles to attend the golden jubilee (50th anniversary) of the island nation's National Day as Guest of Honour. The visit underscores India's deepening ties with Indian Ocean island nations under its 'Neighbourhood First' and SAGAR (Security and Growth for All in the Region) policy. During the visit, Modi was also scheduled to meet Jonathan, widely recognised as the world's oldest living land animal — a giant tortoise aged approximately 192 years.", "exam_angle": "India's diplomatic outreach to Indian Ocean island states is a recurring IR theme; connects to SAGAR doctrine, blue economy, and India's maritime neighbourhood strategy.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Occasion: Golden Jubilee (50th anniversary) of Seychelles' National Day", "PM Modi attended as Guest of Honour", "Connects to India's SAGAR policy and Indian Ocean outreach", "Jonathan the tortoise (~192 years old) — world's oldest living land animal — met during visit"], "source": "NDTV / The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "US Secretary of State Rubio Confirms Trump Likely to Visit India in Early 2027; India-US Trade Deal Near Finalisation", "category": "ir", "category_name": "International Relations", "summary": "US Secretary of State Marco Rubio stated that President Donald Trump is likely to visit India in early 2027, describing his relationship with PM Modi as excellent. Rubio also indicated that an India-US bilateral trade deal is close to finalisation, with only a 'handful of issues' remaining. US Ambassador to India Sergio Gor separately noted that H-1B visa restrictions were not India-specific. The announcements signal a significant upswing in India-US strategic and economic engagement.", "exam_angle": "India-US bilateral trade relations, BTA negotiations, and high-level diplomatic visits are standard UPSC IR topics; connects to Quad, Indo-Pacific strategy, and technology partnership.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Trump India visit expected: early 2027 (per Rubio)", "India-US trade deal described as near-finalisation", "US envoy: H-1B curbs not India-specific", "Marco Rubio is US Secretary of State; Sergio Gor is US Ambassador to India"], "source": "The Economic Times / The Hindu / NDTV", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India Launches 'Operation Amistad' — Sends Humanitarian Relief to Earthquake-Hit Venezuela", "category": "ir", "category_name": "International Relations", "summary": "India dispatched relief material to Venezuela under 'Operation Amistad' (meaning 'friendship' in Spanish) following a devastating earthquake that killed over 920 people. The operation demonstrates India's Humanitarian Assistance and Disaster Relief (HADR) capabilities and its broader global outreach. Venezuela's president expressed confidence in rescue operations as the 72-hour rescue window neared its end.", "exam_angle": "India's HADR missions are a key IR and defence topic; 'Operation Amistad' can be asked as an example of India's soft power and disaster diplomacy in Latin America.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Operation name: Operation Amistad ('friendship')", "Triggered by: Venezuela earthquake (death toll 920+)", "India provided: humanitarian relief material", "Demonstrates India's HADR capability beyond immediate neighbourhood"], "source": "The Quint", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India-New Zealand Free Trade Agreement Under Discussion as Modern Trade Partnership", "category": "economy", "category_name": "Economy & Banking", "summary": "Discussions around an India-New Zealand Free Trade Agreement (FTA) have been highlighted as a potential 'modern trade partnership', covering goods, services, and digital trade. The FTA is part of India's broader strategy of securing bilateral trade agreements with key partners amid global trade realignments. India has been actively pursuing FTAs with the UK, EU, and several other nations in recent years.", "exam_angle": "India's FTA strategy is a major GS-3 economy and GS-2 IR topic; the New Zealand FTA adds to the list of ongoing negotiations students must track alongside UK-FTA, EU-FTA, and GCC-FTA.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["India-New Zealand FTA: described as a 'modern trade partnership'", "Covers goods, services, and digital trade components", "Part of India's active bilateral FTA strategy", "Other ongoing FTAs: UK, EU, Canada, GCC"], "source": "The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India Starts World's First Hydrogen Production Facility Using Nuclear Technology", "category": "scitech", "category_name": "Science & Technology", "summary": "India has commissioned what is being described as the world's first hydrogen production facility that uses nuclear technology, marking a significant milestone in clean energy. The facility leverages high-temperature nuclear reactors to produce hydrogen through thermochemical or electrolysis processes, offering a carbon-free hydrogen production pathway. This aligns with India's National Green Hydrogen Mission and its net-zero commitments.", "exam_angle": "Nuclear energy and green hydrogen are high-priority GS-3 Sci-Tech and environment topics; this development directly connects to India's National Green Hydrogen Mission (NGHM) and energy security.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Claimed to be: world's first nuclear-technology-based hydrogen production facility", "Technology: nuclear energy used for clean hydrogen production", "Connects to: National Green Hydrogen Mission (NGHM)", "Significance: carbon-free hydrogen pathway for India's energy transition"], "source": "The Business Standard", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Indian Navy's Eastern Fleet Ships Arrive at Sattahip, Thailand for Port Visit", "category": "defence", "category_name": "Defence & Security", "summary": "Three ships of the Indian Navy's Eastern Fleet — INS Udaygiri, INS Kavaratti, and INS Shakti — arrived at Sattahip Naval Base in Thailand. Such port visits are part of India's naval diplomacy under the SAGAR framework and strengthen maritime partnerships in the Indo-Pacific region. The visit enhances defence cooperation and interoperability between Indian and Thai naval forces.", "exam_angle": "Indian Navy port visits to Indo-Pacific nations are standard UPSC defence and IR questions; INS Udaygiri (destroyer) and INS Kavaratti (ASW corvette) are frequently asked warship names.", "gs_paper": "GS Paper 3 (Defence)", "key_facts": ["Ships: INS Udaygiri, INS Kavaratti, INS Shakti", "Fleet: Eastern Fleet", "Port visited: Sattahip Naval Base, Thailand", "Context: naval diplomacy under SAGAR / Indo-Pacific engagement"], "source": "PIB", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Anthropic's Mythos AI Model Receives Limited US Government Approval for Broader Use", "category": "scitech", "category_name": "Science & Technology", "summary": "The US government approved limited broader access to Anthropic's advanced AI model 'Mythos 5' after initially blocking its release over national security concerns. The Trump administration granted the approval with security safeguards in place, following Anthropic briefing the government on the model's capabilities. Separately, OpenAI announced new AI models named Sol, Terra, and Luna, with the US government restricting their wide release due to security implications.", "exam_angle": "AI governance and national security dimensions of frontier AI models are emerging Sci-Tech and IR topics for UPSC; connects to AI regulation, export controls, and responsible AI deployment.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Anthropic's AI model: Mythos 5 — received limited US approval after national security review", "OpenAI new models announced: Sol, Terra, Luna — US blocked wide release", "Issue: national security concerns over powerful frontier AI models", "Trend: governments increasingly regulating export and deployment of advanced AI"], "source": "Business Standard / India Today / The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Kotak Mahindra Bank MD & CEO Ashok Vaswani to Step Down at Year-End", "category": "economy", "category_name": "Economy & Banking", "summary": "Ashok Vaswani, the Managing Director and Chief Executive Officer of Kotak Mahindra Bank, announced he will step down at the end of his current term in December 2026 for personal reasons. The bank has begun the search for his successor. Vaswani had taken charge of the private sector bank in January 2024, succeeding founder Uday Kotak who stepped down as CEO.", "exam_angle": "Leadership changes at major private sector banks are relevant for economy and banking awareness; RBI's 'fit and proper' norms for bank CEOs and succession planning at systemically important banks are standard exam topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Kotak Mahindra Bank CEO: Ashok Vaswani stepping down end of 2026", "Reason: personal", "Vaswani joined: January 2024 (succeeded founder Uday Kotak)", "Kotak Mahindra Bank: one of India's largest private sector banks"], "source": "Moneycontrol / The Economic Times", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Maharashtra Teacher Eligibility Test (TET) 2026 Postponed After Paper Leak Suspicion", "category": "polity", "category_name": "Polity & Governance", "summary": "The Maharashtra Teacher Eligibility Test (TET) 2026 was postponed just one day before the scheduled examination date following suspicion of a paper leak originating from Bhiwandi. The incident adds to a series of high-profile examination paper leak controversies in India. The Maharashtra government faced sharp criticism, with opposition parties and educators questioning the integrity of public examinations.", "exam_angle": "Examination integrity, paper leak prevention mechanisms, and the role of state PSC/examination boards are polity and governance topics; connects to the Public Examinations (Prevention of Unfair Means) Act 2024 enacted by Parliament.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Exam postponed: Maharashtra TET 2026", "Reason: suspicion of paper leak (source traced to Bhiwandi)", "Timing: postponed one day before scheduled exam", "Central law context: Public Examinations (Prevention of Unfair Means) Act, 2024"], "source": "Hindustan Times / The Hindu", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Haryana IAS Officer Suspended After CBI Arrest in Rs 657-Crore IDFC Bank Scam", "category": "polity", "category_name": "Polity & Governance", "summary": "The Haryana government suspended an IAS officer following their arrest by the Central Bureau of Investigation (CBI) in connection with a Rs 657-crore scam involving IDFC Bank. The case relates to alleged financial fraud and misuse of public funds. The suspension under All India Services (Discipline and Appeal) Rules follows standard protocol when an AIS officer is placed under arrest.", "exam_angle": "IAS officer accountability, All India Services rules, CBI jurisdiction over public servants, and anti-corruption mechanisms are standard GS-2 polity/governance topics.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Arrested by: CBI", "Scam amount: Rs 657 crore (IDFC Bank-related)", "Action taken: suspension by Haryana government", "Applicable rules: All India Services (Discipline and Appeal) Rules"], "source": "India Today", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "India's Gaza Policy Debate: BJP-Congress Exchange as India Maintains Balanced Stand", "category": "ir", "category_name": "International Relations", "summary": "The BJP defended India's policy on the Gaza conflict as 'balanced', while Congress accused the government of playing vote-bank politics. India has traditionally maintained a two-state solution stance and called for cessation of hostilities, while also deepening its strategic ties with Israel. Simultaneously, Mirwaiz Umar Farooq, the chief religious leader of Kashmir, called for direct India-Pakistan talks.", "exam_angle": "India's West Asia policy — the Israel-Palestine question and the two-state solution — is a recurring UPSC IR topic; India's historical non-alignment-derived stance of supporting Palestine while maintaining Israel ties is frequently examined.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's stated position: balanced, supports two-state solution", "BJP characterisation: Congress doing vote-bank politics on Gaza", "India's Israel ties: deepened post-2017 (PM Modi's historic Israel visit)", "Mirwaiz Umar Farooq: called for direct India-Pakistan dialogue"], "source": "The Hindu / NDTV", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Oil Tanker Struck in Strait of Hormuz Amid Iran-US Military Exchange", "category": "ir", "category_name": "International Relations", "summary": "An oil tanker was struck by an 'unknown projectile' in the strategically critical Strait of Hormuz as Iran and the United States exchanged military strikes. Iran condemned the US strikes as a 'blatant violation of the peace deal'. The Strait of Hormuz is the world's most important oil chokepoint through which approximately 20% of global oil trade passes, making any conflict there highly significant for global energy markets including India.", "exam_angle": "The Strait of Hormuz as a global chokepoint, Iran-US tensions, and their impact on India's energy security and crude oil imports are critical GS-2 IR and GS-3 Economy topics.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Location: Strait of Hormuz — world's most critical oil chokepoint (~20% global oil trade)", "Incident: oil tanker hit by unknown projectile", "Context: Iran-US military exchange", "Iran's statement: US strikes are 'blatant violation of peace deal'"], "source": "NDTV", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "NEP 2020 and India's Education Crisis: Implementation Challenges Examined", "category": "polity", "category_name": "Polity & Governance", "summary": "A detailed analysis by Frontline Magazine examined the implementation challenges of the National Education Policy (NEP) 2020 and India's broader education crisis. NEP 2020 envisions a transformation from rote learning to competency-based education, multidisciplinary approach, a 5+3+3+4 school structure, and a target of 50% Gross Enrolment Ratio in higher education by 2035. Issues such as teacher shortages, infrastructure gaps, and regional disparities in implementation have been highlighted.", "exam_angle": "NEP 2020 is one of the most frequently asked governance/education topics in UPSC GS-2; key provisions, pillars, and implementation gaps are must-know for aspirants.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["NEP 2020: approved by Union Cabinet in July 2020", "Structural change: 10+2 replaced by 5+3+3+4 curricular framework", "GER target: 50% in higher education by 2035 (from ~27% currently)", "Key pillars: mother tongue as medium of instruction (till Class 5), multidisciplinary education, vocational training from Class 6"], "source": "Frontline Magazine", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Qatar Repatriates All 12 Bodies of Indians Killed in Ras Laffan Gas Facility Fire", "category": "ir", "category_name": "International Relations", "summary": "Qatar completed the repatriation of all 12 bodies of Indian nationals killed in a fire at the Ras Laffan industrial complex, home to some of the world's largest liquefied natural gas (LNG) facilities. All 12 bodies have now been brought back to India. Ras Laffan Industrial City in Qatar is one of the world's largest concentrations of energy infrastructure, and India is a major buyer of Qatari LNG.", "exam_angle": "Indian diaspora welfare, India-Qatar bilateral relations (India is Qatar's largest source of migrant labour), and Ras Laffan as a strategic LNG hub are relevant IR and economy angles.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Incident: fire at Ras Laffan Industrial Complex, Qatar", "Casualties: 12 Indian nationals killed", "All 12 bodies repatriated to India", "Ras Laffan: one of world's largest LNG production hubs; Qatar is major LNG supplier to India"], "source": "The New Indian Express / India Today", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Hyderabad Names Road After US President Trump; Trump Thanks India", "category": "ir", "category_name": "International Relations", "summary": "A road in Hyderabad was named after US President Donald Trump, prompting Trump to publicly thank India and call it an 'unprecedented honour'. The gesture reflects the warm personal rapport between PM Modi and President Trump, which has been emphasised in diplomatic communication. Such symbolic acts of diplomatic goodwill, while ceremonial, signal the direction of bilateral relations.", "exam_angle": "India-US bilateral diplomacy and the role of soft power gestures in foreign policy are GS-2 IR topics; this can be used as an example of people-to-people diplomacy.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Road named after: US President Donald Trump", "City: Hyderabad", "Trump's response: called it 'unprecedented honour', publicly thanked India", "Context: warm Modi-Trump bilateral relationship ahead of potential 2027 state visit"], "source": "The Quint / India Today", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "MDMK Quits DMK-Led Alliance in Tamil Nadu After 9 Years", "category": "polity", "category_name": "Polity & Governance", "summary": "The Marumalarchi Dravida Munnetra Kazhagam (MDMK), led by Vaiko, quit the DMK-led alliance in Tamil Nadu after nine years, citing political differences. This is a setback for Chief Minister MK Stalin's DMK ahead of future state elections. Tamil Nadu coalition politics is significant given the state's complex multi-party system and the role of regional parties in national politics.", "exam_angle": "Coalition dynamics, regional party politics, and the role of Tamil Nadu's multi-party system are polity topics; MDMK-DMK relations and Tamil Nadu's political landscape are frequently examined in State PSC exams.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["MDMK: Marumalarchi Dravida Munnetra Kazhagam, led by Vaiko", "Alliance quit after: 9 years with DMK", "Tamil Nadu CM: MK Stalin (DMK)", "Significance: potential impact on INDIA bloc and Tamil Nadu electoral arithmetic"], "source": "NDTV", "day": "2026-06-27", "day_label": "27 Jun"}, {"title": "Government Releases Names of Six Soldiers Killed During Operation Sindoor", "category": "defence", "category_name": "Defence & Security", "summary": "The Indian government publicly released the names of six military personnel killed in action during Operation Sindoor for the first time. This marks an official acknowledgement of personnel casualties from the operation. The disclosure was widely reported by NDTV, The Hindu, and Scroll.in on June 26, 2026. Operation Sindoor had previously been in the news for India's military actions against Pakistan-based terror infrastructure.", "exam_angle": "Operation Sindoor is significant for GS Paper 3 (Internal Security & Defence); questions may arise on India's military operations, casualty disclosure norms, and civil-military relations.", "gs_paper": "GS Paper 3 (Defence & Internal Security)", "key_facts": ["Six military personnel killed in action during Operation Sindoor", "Names released publicly for the first time on June 26, 2026", "Reported by NDTV, The Hindu, Scroll.in"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Mahesh Dixit Appointed as New Chief of Intelligence Bureau", "category": "persons", "category_name": "Persons & Awards in News", "summary": "IPS officer Mahesh Dixit has been appointed as the new chief of the Intelligence Bureau (IB), India's domestic intelligence agency. Dixit is notable for being a doctor-turned-IPS officer, making him India's first medical doctor to head the Intelligence Bureau. He is credited with steady crisis management and consensus-building, particularly in Jammu & Kashmir and Leh. His appointment comes amid a broader cabinet/security establishment reshuffle.", "exam_angle": "IB chief appointments are frequently asked in 'Persons in News' sections; the IB operates under the Ministry of Home Affairs and is India's primary internal intelligence agency — relevant to GS Paper 2 (Governance) and GS Paper 3 (Internal Security).", "gs_paper": "GS Paper 3 (Internal Security)", "key_facts": ["Mahesh Dixit appointed as Intelligence Bureau (IB) chief", "First medical doctor (MBBS) to head IB in India", "IPS officer with experience in J&K and Leh postings", "IB functions under Ministry of Home Affairs"], "source": "Hindustan Times", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Japan PM Sanae Takaichi to Visit India (July 1–3) for Annual India-Japan Summit", "category": "ir", "category_name": "International Relations", "summary": "Japanese Prime Minister Sanae Takaichi is scheduled to visit India from July 1 to 3, 2026, for the Annual India-Japan Summit. The visit is part of the institutionalised annual bilateral summit mechanism between the two countries. India and Japan share a Special Strategic and Global Partnership. Key agenda items are expected to include defence cooperation, infrastructure investment (including bullet train project), and technology collaboration.", "exam_angle": "India-Japan Annual Summit is a recurring exam topic under GS Paper 2 (IR); Japan is India's key partner in defence, infrastructure (bullet train), and QUAD — aspirants must track PM-level visits and outcomes.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Japan PM Sanae Takaichi to visit India: July 1–3, 2026", "Annual India-Japan Summit mechanism", "India-Japan relationship: Special Strategic and Global Partnership", "Japan is QUAD partner along with India, USA, Australia"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India Launches 'Operation Amistad' — Dispatches Relief and Medical Aid to Earthquake-Hit Venezuela", "category": "ir", "category_name": "International Relations", "summary": "India launched 'Operation Amistad' (meaning 'friendship' in Spanish) to dispatch humanitarian relief and medical aid to Venezuela, which was struck by devastating earthquakes with a death toll exceeding 589 and over 2,900 injured. The operation reflects India's growing role as a first responder in international humanitarian crises. India has previously conducted similar operations such as Operation Dost (Turkey/Syria earthquake, 2023) and Operation Kaveri (Sudan, 2023).", "exam_angle": "India's humanitarian diplomacy and disaster relief operations are important for GS Paper 2 (IR); 'Operation Amistad' connects to India's 'Neighbourhood First' and 'Global South' diplomacy narratives.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Operation Amistad: India's relief operation to Venezuela", "Venezuela earthquake toll: 589+ dead, 2,900+ injured (as of June 26, 2026)", "'Amistad' means friendship in Spanish", "Similar past ops: Operation Dost (Turkey, 2023), Operation Kaveri (Sudan, 2023)"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Bangladesh PM and Chinese Water Minister Discuss Teesta River Plan Implementation", "category": "ir", "category_name": "International Relations", "summary": "Bangladesh Prime Minister Tarique Rahman and China's Water Minister held discussions on implementing the Teesta River management plan. China has proposed a $1 billion Teesta River comprehensive management project, which has been a contentious issue in India-Bangladesh-China triangular relations. China also reaffirmed support for Bangladesh's new government and expressed expectations for high-quality Belt and Road Initiative (BRI) cooperation. Bangladesh also urged China to reduce the bilateral trade deficit.", "exam_angle": "The Teesta River dispute is a long-standing India-Bangladesh bilateral issue; China's involvement introduces a strategic triangular dimension critical for GS Paper 2 (IR) — Brahmaputra/Teesta water-sharing and China's BRI expansion in South Asia.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Bangladesh PM Tarique Rahman discussed Teesta Plan with Chinese Water Minister", "China has proposed ~$1 billion Teesta comprehensive management project", "Teesta river originates in Sikkim, flows through West Bengal into Bangladesh", "China's BRI cooperation reaffirmed with Bangladesh's interim government"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "UN Suspends Ship Evacuation in Strait of Hormuz After Attack on Vessel off Oman", "category": "ir", "category_name": "International Relations", "summary": "The United Nations suspended its ship evacuation effort in the Strait of Hormuz after a cargo vessel was attacked off the coast of Oman. Iran was reported to have attacked the cargo ship, testing a recently negotiated US-Iran deal aimed at reopening the Strait. The International Maritime Organization (IMO) had announced an evacuation plan for the area. The Strait of Hormuz is a critical global oil and trade chokepoint through which approximately 20% of global oil supply transits.", "exam_angle": "The Strait of Hormuz is a key strategic chokepoint for global energy security — directly relevant to GS Paper 3 (Energy Security) and GS Paper 2 (IR); India imports significant oil through this route.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["UN suspended ship evacuation in Strait of Hormuz after attack off Oman", "IMO (International Maritime Organization) had announced an evacuation plan", "Strait of Hormuz: ~20% of global oil supply transits through it", "Iran accused of attacking the cargo vessel"], "source": "Telegraph India", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Iran Proposes $40 Billion Plan to Charge Ships Transiting Strait of Hormuz", "category": "ir", "category_name": "International Relations", "summary": "Iran proposed a $40 billion plan to levy charges on ships passing through the Strait of Hormuz, one of the world's most critical maritime chokepoints. The proposal comes amid ongoing tensions in the region following drone strikes and cargo ship attacks. The Strait connects the Persian Gulf to the Arabian Sea and is vital for global oil supply chains. Such a move would have significant implications for global trade and energy markets.", "exam_angle": "Relevant for GS Paper 3 (Economy — Energy Security) and GS Paper 2 (IR); India's energy import vulnerability through the Persian Gulf makes Hormuz-related developments directly exam-relevant.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Iran proposed $40 billion plan to charge vessels transiting Strait of Hormuz", "Strait of Hormuz: key chokepoint between Persian Gulf and Arabian Sea", "Approximately 20-21 million barrels of oil transit daily through the Strait"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "NIA Files Chargesheet Against 11 Bangladeshi Terrorists", "category": "polity", "category_name": "Polity & Governance", "summary": "India's National Investigation Agency (NIA) filed a chargesheet against 11 Bangladeshi nationals accused of terrorism-related offences. The chargesheet is part of NIA's ongoing efforts to counter cross-border terrorism originating from Bangladesh. The NIA operates under the Ministry of Home Affairs and was established under the National Investigation Agency Act, 2008. The development comes against the backdrop of changing political dynamics in Bangladesh following the fall of the Sheikh Hasina government.", "exam_angle": "NIA's mandate, jurisdiction, and counter-terrorism chargesheets are standard GS Paper 3 (Internal Security) topics; Bangladesh-linked terrorism and India's border security challenges are also important.", "gs_paper": "GS Paper 3 (Internal Security)", "key_facts": ["NIA (National Investigation Agency) filed chargesheet against 11 Bangladeshi terrorists", "NIA established under National Investigation Agency Act, 2008", "NIA functions under Ministry of Home Affairs", "Chargesheet relates to cross-border terrorism from Bangladesh"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Europe's 2026 Heatwave 'Virtually Impossible' Without Climate Change, Scientists Confirm", "category": "environment", "category_name": "Environment & Ecology", "summary": "Scientists from World Weather Attribution (WWA) concluded that the 2026 European heatwave was 'virtually impossible' without human-induced climate change, calling it the worst ever recorded. Paris restricted alcohol consumption and sales as temperatures soared. The extreme heat event demonstrates accelerating climate attribution — the science linking specific weather events to climate change. Such rapid-onset extreme weather has implications for public health, agriculture, and energy systems globally.", "exam_angle": "Climate attribution science and extreme weather events are central to GS Paper 3 (Environment); World Weather Attribution (WWA) is a key body to know for reports on climate-weather linkages.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["2026 European heatwave declared 'virtually impossible' without climate change", "Assessed by World Weather Attribution (WWA) scientists", "Declared the worst heatwave ever recorded in Europe", "Paris restricted alcohol sales and consumption during heatwave"], "source": "Reuters", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India-US Trade Deal Talks: Trump Administration Warns Old Tariffs May Return", "category": "economy", "category_name": "Economy & Banking", "summary": "Amid ongoing India-US trade deal negotiations, the Trump administration issued a fresh warning that old (pre-deal) tariffs may return if negotiations fail to conclude favourably. Two-day trade talks were underway with India seeking a competitive edge in US markets, while the US focused on market access and reducing trade deficits. India is seeking preferential tariff treatment especially for its IT, pharmaceuticals, and textile exports. The talks are set against the backdrop of Trump's broader global tariff pressure campaign.", "exam_angle": "India-US trade relations, tariff regimes, and bilateral trade deal negotiations are important for GS Paper 2 (IR) and GS Paper 3 (Economy); WTO, MFN clauses, and trade defence measures are related concepts.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India-US trade deal talks ongoing as of June 26, 2026", "Trump administration warned old tariffs may return if talks fail", "India seeks competitive market access in sectors like IT, pharma, textiles", "US seeks reduced trade deficit and greater market access in India"], "source": "The Times of India", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Goldman Sachs Raises India GDP Growth Forecast to 6.8% for 2026", "category": "economy", "category_name": "Economy & Banking", "summary": "Goldman Sachs raised its GDP growth forecast for India to 6.8% for 2026, partially attributing the upward revision to the US-Iran deal that has helped ease global oil price pressures. Lower crude oil prices benefit India significantly given its heavy dependence on oil imports (~85% of requirements). The revision reflects improving macro conditions and strong domestic demand. India remains one of the fastest-growing major economies globally.", "exam_angle": "GDP forecasts by global institutions (Goldman Sachs, IMF, World Bank) are standard 'reports' questions in UPSC Prelims and GS Paper 3 (Economy); India's crude oil import dependency is a key economic vulnerability.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Goldman Sachs raised India GDP forecast to 6.8% for 2026", "Revision partly attributed to US-Iran deal easing oil prices", "India imports ~85% of its crude oil requirements", "India remains among the fastest-growing major economies"], "source": "Business Standard", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Amazon CEO Andy Jassy Announces $48 Billion Investment Plan for India", "category": "economy", "category_name": "Economy & Banking", "summary": "Amazon CEO Andy Jassy announced a $48 billion investment plan for India, with a significant focus on Amazon Web Services (AWS) cloud infrastructure and Artificial Intelligence. The investment is one of the largest ever announced by a foreign tech company for India. It follows earlier commitments by major tech firms like Google and Microsoft in India's digital infrastructure. The announcement signals India's growing importance as a global technology and cloud services hub.", "exam_angle": "FDI inflows, particularly in technology and cloud infrastructure, are relevant for GS Paper 3 (Economy) and GS Paper 2 (IR — India-US tech relations); Digital India and National Cloud Policy are related government initiatives.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Amazon CEO Andy Jassy announced $48 billion investment in India", "Focus areas: AWS cloud infrastructure and Artificial Intelligence", "One of the largest single-company FDI commitments to India by a tech firm", "Reinforces India's positioning as a global digital and cloud hub"], "source": "News18", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Nasscom: India's AI Services Revenue Reaches $10–12 Billion", "category": "reports", "category_name": "Reports & Indices", "summary": "Industry body Nasscom reported that India's IT companies are generating $10–12 billion in revenue from Artificial Intelligence services, signalling that AI adoption has moved beyond pilots to mainstream deployment. The data reflects India's growing strength in AI-enabled IT services globally. Nasscom is the apex body of the Indian IT industry. This development has implications for India's digital economy targets and employment in the tech sector.", "exam_angle": "Nasscom reports and India's AI/IT industry statistics are important for GS Paper 3 (Economy & Sci-Tech); AI governance, India's National AI Strategy (INDIAai Mission), and digital economy are connected themes.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["India's IT industry AI services revenue: $10–12 billion (Nasscom, 2026)", "AI adoption has moved from pilots to mainstream deployment", "Nasscom: National Association of Software and Service Companies (apex IT industry body)"], "source": "Business Standard", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "RBI's AI Risk Framework to Strengthen Governance and Oversight of AI Models in Banking", "category": "economy", "category_name": "Economy & Banking", "summary": "The Reserve Bank of India (RBI) announced an AI risk framework aimed at strengthening governance and oversight of AI models used by banks and financial institutions. The framework will address risks such as model bias, opacity ('black box' problem), data privacy, and systemic risk from AI in financial decision-making. This is part of RBI's broader regulatory technology (RegTech) initiatives. India's banking sector is increasingly deploying AI for credit underwriting, fraud detection, and customer service.", "exam_angle": "RBI's regulatory frameworks are central to GS Paper 3 (Economy); AI regulation in banking is an emerging topic connecting GS Paper 3 (Sci-Tech) and financial sector governance.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["RBI announced an AI Risk Framework for banks and financial institutions", "Addresses risks: model bias, opacity, data privacy, systemic risk", "Part of RBI's RegTech (Regulatory Technology) initiatives", "RBI regulates commercial banks under RBI Act, 1934 and Banking Regulation Act, 1949"], "source": "Business Standard", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India Tops Medal Tally at ISSF Junior World Championship in Germany", "category": "reports", "category_name": "Reports & Indices", "summary": "India's shooters topped the medal tally at the ISSF (International Shooting Sport Federation) Junior World Championship held in Germany. India's shooting contingent has been consistently performing at the international level, building on successes at the 2024 Paris Olympics where Indian shooters won multiple medals. The ISSF Junior World Championship is a key feeder competition for the senior international circuit and Olympics qualification.", "exam_angle": "India's performance in international shooting championships is relevant for Prelims 'Sports' current affairs; ISSF and Olympic shooting qualification processes are associated concepts.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["India topped medal tally at ISSF Junior World Championship 2026", "Championship held in Germany", "ISSF: International Shooting Sport Federation (governing body for Olympic shooting)"], "source": "The Times of India", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Nihang Sikhs Breach Barricades at Uttarakhand Border, Standoff Resolved After Talks", "category": "polity", "category_name": "Polity & Governance", "summary": "A tense standoff occurred at Uttarakhand's border when Nihang Sikhs breached police barricades while heading towards Hemkund Sahib, a prominent Sikh shrine located in Chamoli district at an altitude of 4,329 metres in the Himalayas. The situation normalised after talks between Nihang groups and police, and those involved left without further incident. Hemkund Sahib is associated with Guru Gobind Singh and is mentioned in the Dasam Granth. The episode raised questions about management of pilgrimage routes and law enforcement.", "exam_angle": "Hemkund Sahib and Nihang Sikhs connect to GS Paper 1 (Culture/Art & Heritage) and GS Paper 2 (Polity — law & order, federalism); places of religious significance in Uttarakhand are frequently asked.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["Nihang Sikhs breached barricades at Uttarakhand border heading to Hemkund Sahib", "Hemkund Sahib: Sikh shrine in Chamoli district, Uttarakhand at ~4,329 m altitude", "Standoff resolved after talks; Nihangs left peacefully", "Hemkund Sahib associated with Guru Gobind Singh (mentioned in Dasam Granth)"], "source": "The Hindu", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Micromax-Phison JV 'MiPhi' Plans Rs 1,000 Crore Investment in AI Memory Chip Manufacturing", "category": "scitech", "category_name": "Science & Technology", "summary": "MiPhi, a joint venture between India's Micromax and Taiwan's Phison Electronics, announced plans to invest Rs 1,000 crore in India's AI memory chip sector. The investment aims to capitalise on India's growing AI infrastructure boom and aligns with the government's India Semiconductor Mission (ISM) to develop domestic semiconductor manufacturing capabilities. India has been actively attracting semiconductor companies with financial incentives under the Semicon India Programme. The move signals growing confidence in India as a destination for advanced chip manufacturing.", "exam_angle": "India Semiconductor Mission, Semicon India Programme, and domestic chip manufacturing are important for GS Paper 3 (Sci-Tech & Economy); semiconductor geopolitics is an emerging UPSC theme.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["MiPhi JV (Micromax + Phison Electronics) to invest Rs 1,000 crore in AI memory chips", "Aligns with India Semiconductor Mission (ISM) under Ministry of Electronics & IT", "Semicon India Programme provides ~50% fiscal support for chip manufacturing", "Phison Electronics is a Taiwan-based NAND flash controller chip company"], "source": "Moneycontrol", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Indian Air Force Assists Rescue Operations After Flash Floods in Arunachal Pradesh", "category": "defence", "category_name": "Defence & Security", "summary": "The Indian Air Force (IAF) deployed aircraft to assist rescue and relief operations following flash floods in Arunachal Pradesh. Flash floods are a recurring disaster in Arunachal Pradesh due to its mountainous terrain, high rainfall, and glacial lake outburst floods (GLOFs). The IAF regularly plays a critical role in disaster relief operations in the Northeast and other difficult terrains under the framework of civil-military coordination in disaster management. The NDRF and SDRF typically operate alongside military forces in such situations.", "exam_angle": "IAF's role in disaster relief and civil-military cooperation in NDMA framework are relevant for GS Paper 3 (Disaster Management); Arunachal Pradesh's vulnerability to GLOFs and flash floods is relevant for GS Paper 1 (Geography).", "gs_paper": "GS Paper 3 (Disaster Management)", "key_facts": ["IAF deployed for rescue operations after Arunachal Pradesh flash floods", "Flash floods common in Arunachal due to GLOFs (Glacial Lake Outburst Floods) and heavy rainfall", "IAF operates under Ministry of Defence; disaster relief under NDMA framework", "NDRF (National Disaster Response Force) also deploys in such emergencies"], "source": "NDTV", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Piyush Goyal Questions Global Credit Rating Agencies Over Undervaluation of India's Growth Story", "category": "economy", "category_name": "Economy & Banking", "summary": "Union Minister Piyush Goyal publicly questioned the credibility and methodology of global credit rating agencies, stating that India's growth story has been chronically undervalued by these agencies. India has long maintained that its sovereign credit rating (Baa3/BBB- by Moody's/S&P/Fitch — lowest investment grade) does not accurately reflect its macroeconomic fundamentals and growth trajectory. India has previously submitted detailed rebuttals to rating agencies through the Ministry of Finance. The statement reflects ongoing tension between India's economic performance and its international credit standing.", "exam_angle": "Sovereign credit ratings, their methodology, and India's rating dispute are important for GS Paper 3 (Economy); Moody's, S&P, Fitch are the 'Big Three' rating agencies — frequently mentioned in economic editorials.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Minister Piyush Goyal criticised global credit rating agencies for undervaluing India", "India's sovereign rating: Baa3 (Moody's), BBB- (S&P/Fitch) — lowest investment grade", "India has formally challenged rating methodologies through Ministry of Finance", "Big Three rating agencies: Moody's, S&P Global, Fitch Ratings"], "source": "Moneycontrol", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "India Pushes for Stable AI Technology Access from USA After Mythos Suspension", "category": "scitech", "category_name": "Science & Technology", "summary": "India has formally pushed for stable and uninterrupted access to AI technology from the United States following the suspension of 'Mythos', an AI system that India was accessing. The move reflects India's strategic interest in not being dependent on a single AI supplier and ensuring technology sovereignty. This connects to India's broader push for AI governance frameworks and its National AI Strategy. India is seeking to be included in the US's trusted AI partner framework amid growing US-China AI competition.", "exam_angle": "AI technology access, technology sovereignty, and India-US tech diplomacy are relevant for GS Paper 2 (IR) and GS Paper 3 (Sci-Tech); India's INDIAai Mission and National AI Strategy are related government initiatives.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["India pushing USA for stable AI technology access after 'Mythos' AI suspension", "Reflects concern over technology dependency and AI sovereignty", "India's National AI Strategy overseen by NITI Aayog's INDIAai Mission", "Relevant to India-US Initiative on Critical and Emerging Technology (iCET)"], "source": "MediaNama", "day": "2026-06-26", "day_label": "26 Jun"}, {"title": "Venezuela Declares State of Emergency After Strongest Twin Earthquakes Since 1900", "category": "places", "category_name": "Places in News", "summary": "Venezuela was struck by two major earthquakes on June 25, 2026, with the event described as the strongest seismic activity in the country since 1900. Thousands are feared dead and President Nicolás Maduro declared a state of emergency. Rescue operations are underway amid scenes of widespread destruction. The international community, including the UN, has responded to the crisis.", "exam_angle": "Significant for GS Paper 1 (Geography) — questions on seismic zones, tectonic plate boundaries (Caribbean Plate), and disaster management frameworks. Also relevant for IR given Venezuela's geopolitical significance.", "gs_paper": "GS Paper 1 (Geography)", "key_facts": ["Strongest earthquake in Venezuela since 1900", "Venezuela declared state of emergency on June 25, 2026", "Thousands feared dead; UN announced evacuation operations", "Venezuela lies near the Caribbean–South American tectonic plate boundary"], "source": "Reuters / BBC / The Guardian", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India–US Trade Deal: Piyush Goyal Sets 'Comparative Tariff Advantage' as Red Line", "category": "ir", "category_name": "International Relations", "summary": "Union Commerce Minister Piyush Goyal stated on June 25, 2026 that India will not sign a trade deal with the United States unless it secures a comparative tariff advantage over competing nations. India and the US concluded the latest round of talks without finalising a deal. Goyal described the deal as 'very close' but stressed that India needs tariff rates lower than competitors like China and Vietnam. Bloomberg reported 'no clarity' on timing after the latest talks concluded.", "exam_angle": "Core IR + Economy topic: India's trade negotiation strategy, Most Favoured Nation (MFN) principles, and bilateral trade relations under the Trump administration's tariff regime are frequently tested.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's condition: comparative tariff advantage framework must be ensured", "Minister involved: Piyush Goyal (Commerce & Industry)", "Talks described as 'very close' to deal but no finalisation as of June 25, 2026", "Key competition cited: China and Vietnam on US tariff rates"], "source": "The Times of India / The Hindu / NDTV / Bloomberg", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India Resumes Tourist Visas for Bangladeshi Nationals; Envoy Dinesh Trivedi Elevated to Union Minister Rank", "category": "ir", "category_name": "International Relations", "summary": "India announced the resumption of tourist visas for Bangladeshi nationals on June 25, 2026, signalling an easing of bilateral ties after a period of strain following the political transition in Bangladesh. India's new envoy to Bangladesh, Dinesh Trivedi, assumed office and announced the visa resumption. The Centre elevated Trivedi to Union Minister rank for ceremonial protocol purposes. This development comes amid broader diplomatic recalibration between the two neighbours.", "exam_angle": "India–Bangladesh bilateral relations are a staple GS Paper 2 (IR) topic; connects to neighbourhood-first policy, SAARC dynamics, and role of diplomacy in managing post-Hasina Bangladesh.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's envoy to Bangladesh: Dinesh Trivedi", "Trivedi elevated to Union Minister rank for ceremonial protocol", "Tourist visas to Bangladeshi nationals resumed: June 2026", "Signals easing of India–Bangladesh ties after 2024 political transition in Dhaka"], "source": "The Times of India / The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India Withdraws Commercial LPG Supply Restrictions Amid US–Iran Deal Hopes", "category": "economy", "category_name": "Economy & Banking", "summary": "India lifted restrictions on commercial LPG supplies to industries on June 25, 2026, a move linked to improving prospects of a US–Iran nuclear/sanctions deal that could ease global energy supplies. Petroleum Minister Hardeep Puri also discussed 'opportunities to cooperate' with his Iranian counterpart after years of curtailed trade due to US sanctions. India had previously curtailed LPG supply to industries to manage domestic shortfall risks. The move signals a recalibration of India's energy security strategy.", "exam_angle": "Connects GS Paper 3 (Energy Security) with GS Paper 2 (IR): India's dependence on West Asian energy, impact of US sanctions on Iranian oil imports, and India's hedging strategy in the Iran–US standoff.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["India lifted commercial LPG supply restrictions: June 25, 2026", "Petroleum Minister: Hardeep Puri", "Trigger: expected US–Iran deal easing global energy markets", "India had drastically reduced Iranian oil imports post-2019 US sanctions (CAATSA concerns)"], "source": "Hindustan Times / Reuters / The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Passport Fee Revised from July 1, 2026: New Passport to Cost Rs 2,500; Tatkaal Rs 5,000", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Government of India announced a revision of passport fees effective July 1, 2026. A fresh/new passport will cost Rs 2,500 (up from earlier rates), while the Tatkaal (urgent) passport fee has been set at Rs 5,000. The fee structure covers both fresh and re-issued documents. The revision is the first significant update to passport fees in several years.", "exam_angle": "Relevant for GS Paper 2 (Governance/Schemes): Passports Act 1967, passport as a citizen-service delivery reform, and e-governance initiatives under MEA. The passport–citizenship distinction (a concurrent legal debate) also tested.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["New passport fee (from July 1, 2026): Rs 2,500", "Tatkaal passport fee: Rs 5,000", "Applies to both fresh issuance and re-issue", "Passports are governed by the Passports Act, 1967"], "source": "Moneycontrol / India Today", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Ram Temple Donation Row: Supreme Court Asks Petitioner to Mention Plea on June 29", "category": "polity", "category_name": "Polity & Governance", "summary": "The Supreme Court of India on June 25, 2026 directed a petitioner seeking a fair probe into alleged embezzlement of donations at the Ram Temple (Ayodhya) to mention the matter on June 29. An FIR has been lodged regarding alleged misappropriation of donations, and two individuals have been arrested. The petitioner has alleged that the SIT formed to investigate the matter is an 'eyewash.' The case involves the Shri Ram Janmabhoomi Teerth Kshetra Trust.", "exam_angle": "Connects to GS Paper 2 (Polity): Supreme Court's supervisory jurisdiction, PIL mechanisms, and accountability of religious trusts. Also relevant for questions on Ayodhya verdict implementation and institutional governance.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["SC directed petitioner to mention plea on June 29, 2026", "FIR lodged for alleged embezzlement of Ram Temple donations", "Two persons arrested in the donations theft case", "Trust involved: Shri Ram Janmabhoomi Teerth Kshetra Trust"], "source": "The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "CBI Conducts Searches at 80+ Locations Across 16 States Under 'Operation Chakra-VI' Against Digital Arrest Scams", "category": "polity", "category_name": "Polity & Governance", "summary": "The Central Bureau of Investigation (CBI) launched 'Operation Chakra-VI' on June 25, 2026, conducting searches at over 80 locations across 16 states to crack down on pan-India 'digital arrest' scam networks. Digital arrest scams involve fraudsters posing as law enforcement officials and coercing victims into transferring money under the guise of a fake arrest. The operation targeted key nodes of the cybercrime syndicate. This is the sixth iteration of Operation Chakra, CBI's ongoing series targeting organised cybercrime.", "exam_angle": "GS Paper 3 (Internal Security/Cybersecurity): Digital arrest scams are a growing cybercrime category; CBI's Operation Chakra series, IT Act provisions, and India's cybercrime institutional framework are testable topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Operation name: Operation Chakra-VI", "Agency: CBI", "Searches: 80+ locations across 16 states (June 25, 2026)", "Target: 'Digital arrest' scam syndicates — fraudsters impersonating police/ED/CBI to extort victims"], "source": "The Hindu / The New Indian Express / The Times of India", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Canada Officially Attributes 1985 Air India Bombing to Khalistanis for the First Time", "category": "ir", "category_name": "International Relations", "summary": "Canada officially stated for the first time that Khalistani extremists were responsible for the 1985 Air India Flight 182 bombing, which killed 329 people — the deadliest terrorist attack in Canadian history and the deadliest aviation attack before 9/11. This marks a significant diplomatic and legal development in India–Canada relations, as India had long maintained that Canada-based Khalistani groups were behind the attack. The declaration comes amid ongoing India–Canada tensions over the Nijjar case.", "exam_angle": "High-value IR topic: India–Canada relations, Khalistani extremism, Five Eyes intelligence, and state accountability for diaspora terrorism. Connects to GS Paper 2 (IR) and GS Paper 3 (Internal Security).", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Air India Flight 182 bombed: June 23, 1985; 329 killed", "Canada's first official attribution of the bombing to Khalistani groups: June 2026", "The attack remains Canada's deadliest terrorist incident", "Context: India–Canada diplomatic tensions over Hardeep Singh Nijjar case (2023–present)"], "source": "India Today", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "NIA: Pahalgam Terror Attack Plot Was in Motion a Week Before Strike; April 15 Reconnaissance Trip Confirmed", "category": "defence", "category_name": "Defence & Security", "summary": "The National Investigation Agency (NIA) revealed on June 25, 2026 that the Pahalgam terror attack plot was in motion at least a week before the strike, with a reconnaissance trip conducted on April 15, 2026. The NIA's findings detail pre-attack planning and surveillance by the perpetrators. The Pahalgam attack, which targeted tourists in the Baisaran valley of Jammu & Kashmir, triggered a major security and diplomatic crisis between India and Pakistan.", "exam_angle": "GS Paper 3 (Internal Security): NIA's investigative role, cross-border terrorism, India–Pakistan relations post-Pahalgam, and counter-terrorism institutional framework are highly testable.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["NIA confirmed: Pahalgam attack plot active at least one week before the strike", "Reconnaissance trip: April 15, 2026 (approximately one week before the attack)", "Attack location: Baisaran valley, Pahalgam, Jammu & Kashmir", "Investigating agency: National Investigation Agency (NIA)"], "source": "The Indian Express", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Strait of Hormuz Crisis: IMO Announces Evacuation Plan for Stranded Seafarers", "category": "ir", "category_name": "International Relations", "summary": "The International Maritime Organization (IMO) announced an evacuation plan on June 25, 2026 for seafarers stranded in the Strait of Hormuz amid the Iran–US military confrontation. The Strait of Hormuz is the world's most critical oil chokepoint, through which approximately 20% of global oil trade passes. Iran had threatened to close the strait, while the US asserted it had ended Iran's ability to do so. The crisis has significant implications for global energy security and India's oil imports.", "exam_angle": "GS Paper 3 (Energy Security) + GS Paper 2 (IR): Strait of Hormuz is a perennially tested geographic chokepoint; IMO's role, freedom of navigation, and India's energy import dependence on the Persian Gulf are key exam angles.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Strait of Hormuz: separates Iran from Oman/UAE; ~20% of global oil trade passes through it", "IMO announced evacuation plan for stranded seafarers: June 25, 2026", "Iran threatened closure of the strait during US–Iran military confrontation", "IMO: International Maritime Organization, UN specialised agency for shipping"], "source": "The Hindu / UN News", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Amazon CEO Andy Jassy Meets PM Modi; Amazon to Invest $48 Billion in India by 2030", "category": "economy", "category_name": "Economy & Banking", "summary": "Amazon CEO Andy Jassy met Prime Minister Narendra Modi on June 25, 2026 and announced that Amazon will invest $48 billion in India by 2030, covering cloud infrastructure, logistics, digital payments, and other verticals. This is one of the largest foreign direct investment commitments made to India by a technology company. The announcement aligns with India's push to attract global tech investments and strengthen its digital economy.", "exam_angle": "GS Paper 3 (Economy): Foreign Direct Investment (FDI) policy, India's digital economy targets, cloud computing infrastructure, and Make in India/Digital India initiatives are testable connections.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Amazon investment commitment: $48 billion in India by 2030", "Amazon CEO: Andy Jassy", "Meeting: with PM Narendra Modi, June 25, 2026", "Covers cloud infrastructure, logistics, and digital ecosystem expansion"], "source": "News18 / NDTV", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "RBI Directs Banks to Install 'Kill Switches' and Human Oversight Mechanisms for AI Models", "category": "economy", "category_name": "Economy & Banking", "summary": "The Reserve Bank of India (RBI) has directed banks to incorporate 'kill switches' — emergency shutdown mechanisms — and mandatory human oversight for AI models deployed in banking operations. The directive is part of RBI's evolving regulatory framework for responsible AI use in the financial sector. This follows global concerns about AI-driven financial decisions and systemic risks. The move aligns with international standards on AI governance in critical financial infrastructure.", "exam_angle": "GS Paper 3 (Economy/Sci-Tech): RBI's regulatory role, AI governance in banking, financial stability, and the intersection of technology regulation with monetary policy are increasingly tested.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["RBI directive: banks must add 'kill switches' and human oversight for AI models", "Purpose: risk mitigation and accountability in AI-driven banking decisions", "Aligns with global AI governance frameworks (e.g., EU AI Act principles)", "Regulatory body: Reserve Bank of India (RBI)"], "source": "MediaNama", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "OpenAI Unveils Custom AI Chip 'Jalapeno' to Reduce Dependence on Nvidia", "category": "scitech", "category_name": "Science & Technology", "summary": "OpenAI unveiled its proprietary AI chip named 'Jalapeno' on June 25, 2026, marking a significant step in the company's strategy to develop in-house semiconductor infrastructure and reduce dependence on Nvidia's GPUs. The chip is designed to accelerate AI model training and inference at scale. This development is part of a broader trend of major AI companies — including Google (TPUs) and Amazon (Trainium) — developing custom chips to gain cost and performance advantages.", "exam_angle": "GS Paper 3 (Sci-Tech): AI chip development, semiconductor geopolitics, US–China chip war, and India's semiconductor mission are testable; OpenAI's vertical integration strategy is a current affairs landmark.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["OpenAI's custom AI chip name: Jalapeno", "Unveiled: June 25, 2026", "Purpose: reduce dependence on Nvidia GPUs for AI training/inference", "Trend: Google (TPU), Amazon (Trainium/Inferentia), Meta (MTIA) — all developing custom AI chips"], "source": "The Hindu", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Anthropic Accuses Alibaba of Illicitly Accessing Claude AI Models via Fake Accounts", "category": "scitech", "category_name": "Science & Technology", "summary": "US AI company Anthropic accused Chinese tech giant Alibaba of illicitly accessing its Claude AI models through fake accounts to extract and replicate AI capabilities — a form of model theft. Anthropic has taken legal action and also announced a shutdown of Alibaba's access. The case highlights the intensifying technological rivalry between US and Chinese AI companies and raises questions about AI intellectual property protection.", "exam_angle": "GS Paper 3 (Sci-Tech) + GS Paper 2 (IR): US–China tech war, AI intellectual property, export controls on AI models, and cybersecurity dimensions of AI development are relevant for UPSC.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Accuser: Anthropic (US AI company, maker of Claude AI)", "Accused: Alibaba (Chinese tech conglomerate)", "Method alleged: fake accounts used to extract Claude AI capabilities", "Broader context: US–China AI technology rivalry and semiconductor/AI export controls"], "source": "Bloomberg / NDTV Profit / Moneycontrol", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India's Future Security to Be Shaped by AI and Quantum Technology: Minister Jitendra Singh", "category": "scitech", "category_name": "Science & Technology", "summary": "Union Minister of State for Science and Technology Jitendra Singh stated on June 25, 2026 that India's future security architecture will be fundamentally shaped by artificial intelligence and quantum technologies. He was speaking in the context of India's national technology missions. India has ongoing missions — the National Quantum Mission (NQM) and IndiaAI Mission — as part of its strategic technology investments to enhance both defence and civilian capabilities.", "exam_angle": "GS Paper 3 (Sci-Tech/Defence): National Quantum Mission, IndiaAI Mission, dual-use technology in defence, and India's technology sovereignty agenda are frequently tested topics.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Statement by: MoS Science & Technology, Dr. Jitendra Singh", "National Quantum Mission (NQM): approved 2023, outlay Rs 6,003 crore over 8 years", "IndiaAI Mission: launched 2024, Rs 10,372 crore over 5 years", "AI and quantum tech identified as pillars of India's future security infrastructure"], "source": "The New Indian Express", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Government Pushes Private Banks to Expand Enrolments Under PMSBY Accident Insurance Scheme", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Government of India has directed private sector banks to significantly expand enrolments under the Pradhan Mantri Suraksha Bima Yojana (PMSBY), an accident insurance scheme providing Rs 2 lakh coverage for Rs 20 annual premium. Private banks have lagged behind public sector banks in enrolment figures. The push is part of the government's financial inclusion and social security agenda. PMSBY was launched in 2015 along with PMJJBY (life insurance) and APY (pension scheme) as part of the Jan Suraksha social security package.", "exam_angle": "GS Paper 2 (Schemes/Governance): Jan Suraksha schemes — PMSBY, PMJJBY, APY — are standard exam topics for their coverage, premium, launch year, and implementing ministry.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Scheme: Pradhan Mantri Suraksha Bima Yojana (PMSBY)", "Coverage: Rs 2 lakh for accidental death/permanent disability; Rs 1 lakh for partial disability", "Annual premium: Rs 20", "Launched: 2015; part of Jan Suraksha package along with PMJJBY and APY"], "source": "Mint", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "Tungabhadra Dam Gets New Spillway Gates; Karnataka, Andhra Pradesh and Telangana Reach Water-Sharing Consensus", "category": "places", "category_name": "Places in News", "summary": "The 33 new spillway gates of the Tungabhadra Dam were inaugurated on June 25, 2026 by Chief Ministers of Karnataka, Andhra Pradesh, and Telangana, signalling a resolution of inter-state water-sharing tensions. The old gates had been a source of dispute and safety concerns. The three states also reached a consensus on water-sharing modalities from the Tungabhadra reservoir. The Tungabhadra Dam is a joint project of Karnataka and the erstwhile undivided Andhra Pradesh, located at Hospet (now Vijayanagara district), Karnataka.", "exam_angle": "GS Paper 2 (Polity/IR): Inter-state river water disputes, role of river water tribunals, and cooperative federalism in managing shared water resources are frequently tested. Tungabhadra is a tributary of the Krishna River.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Tungabhadra Dam location: Hospet, Vijayanagara district, Karnataka", "River: Tungabhadra (tributary of Krishna River)", "33 new spillway gates inaugurated: June 25, 2026", "States involved: Karnataka, Andhra Pradesh, Telangana — reached water-sharing consensus"], "source": "The Hindu / Deccan Chronicle", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "SBI Report: India's Economy Remains Strong Despite Fifth-Driest June in 125 Years", "category": "economy", "category_name": "Economy & Banking", "summary": "A report by the State Bank of India (SBI) released on June 25, 2026 noted that India's economy remains resilient despite June 2026 being the fifth-driest month of June in the past 125 years. The report highlighted India's macroeconomic fundamentals holding up amid global uncertainties, including geopolitical tensions and trade disruptions. The drought-like conditions in June raise concerns about kharif crop output and rural demand but have not yet significantly dented broader economic indicators.", "exam_angle": "GS Paper 3 (Economy/Agriculture): Monsoon's impact on Indian agriculture, kharif crop dependence on June-July rains, and India's economic resilience indicators are important exam themes.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["June 2026: fifth-driest June in 125 years of recorded Indian meteorological history", "Source: SBI Research report, June 2026", "India's economy described as 'strong' despite rainfall deficit", "Concern: impact on kharif sowing, rural incomes, and food inflation"], "source": "Moneycontrol", "day": "2026-06-25", "day_label": "25 Jun"}, {"title": "India Tech Startup Funding Rises 12% to $7.2 Billion in H1 2026, but Deal Count Shrinks", "category": "economy", "category_name": "Economy & Banking", "summary": "India's technology startup ecosystem raised $7.2 billion in funding in the first half of 2026 (H1 2026), a 12% increase year-on-year, according to a Business Standard report. However, the number of individual deals declined, indicating larger deal sizes with fewer but more mature startups receiving capital. The data reflects a trend towards consolidation in the Indian startup ecosystem after the 2022–23 funding winter.", "exam_angle": "GS Paper 3 (Economy): India's startup ecosystem, FDI and venture capital flows, DPIIT's Startup India programme, and India's position in global startup rankings are testable topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["India tech startup funding H1 2026: $7.2 billion (up 12% year-on-year)", "Deal count declined despite higher total funding value", "Indicates consolidation: fewer but larger deals", "India ranks 3rd globally in startup count (after USA and China) per DPIIT data"], "source": "Business Standard", "day": "2026-06-25", "day_label": "25 Jun"}], "categories": [{"id": "polity", "name": "Polity & Governance"}, {"id": "economy", "name": "Economy & Banking"}, {"id": "ir", "name": "International Relations"}, {"id": "environment", "name": "Environment & Ecology"}, {"id": "scitech", "name": "Science & Technology"}, {"id": "schemes", "name": "Govt Schemes & Policies"}, {"id": "defence", "name": "Defence & Security"}, {"id": "reports", "name": "Reports & Indices"}, {"id": "persons", "name": "Persons & Awards in News"}, {"id": "places", "name": "Places in News"}]};